// Worked focus: httpsts-password-verifier-policy — Apply modern password hashing, salt, work policy, input bounds, constant-behavior comparison, breach and reset controls, rehash migration, and secret separation.
// Evidence: httpsts-worked-http-server-ts-authentication-sessions-jose-4
// Competency: httpsts-worked-http-server-ts-authentication-sessions-jose-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_authentication_sessions_jose_4(issuerOk: boolean, audienceOk: boolean, expiresInSeconds: number, sessionRotated: boolean): { principal: string; accepted: boolean } {
  const claimsValid = issuerOk && audienceOk && expiresInSeconds > 0 && expiresInSeconds <= 3600;
  if (!claimsValid) return { principal: "anonymous", accepted: false };
  if (!sessionRotated) return { principal: "stale-session", accepted: false };
  return { principal: "member", accepted: true };
}

